#!/usr/bin/env python3 """Milestone 3 validation crash-restart memory persistence.""" from __future__ import annotations import gc import hashlib import sys import tempfile from pathlib import Path SCRIPTS = Path(__file__).resolve().parent sys.path.insert(0, str(SCRIPTS)) ERRORS: list = [] def check(name: str, cond: bool, detail: str = "") -> None: if cond: print(f" PASS {name}") else: ERRORS.append(f"{name}: {detail}") print(f" FAIL {name} {detail}") def _mock_embed(text: str, dim: int = 768): vals = [0.0] * dim for word in text.lower().split(): digest = hashlib.md5(word.encode("utf-8")).digest() for i in range(8): idx = (digest[i] + i * 31) % dim vals[idx] += 1.0 norm = sum(v * v for v in vals) ** 0.5 or 1.0 return [v / norm for v in vals] def test_checkpoint_and_hydrate() -> None: print("\n--- Checkpoint + Hydrate ---") import sovereign_memory_manager as smm smm._MANAGER = None smm._BOOT_HYDRATION = None with tempfile.TemporaryDirectory() as tmp: db = Path(tmp) / "session_state.sqlite" mgr = smm.SovereignMemoryManager(db) sid = mgr.ensure_active_session("crash-test") mgr.checkpoint( session_id=sid, working_memory=[ {"role": "user", "content": "Index the fleet procurement documents"}, {"role": "assistant", "content": "Starting ingestion pipeline step 2 of 5"}, ], procedural_state={ "active_task": "milestone_3_ingestion", "step": 2, "total_steps": 5, "pending_delegations": ["subagent:vector-index"], }, ) mgr.close() # Simulate process crash new manager instance, same DB smm._MANAGER = None mgr2 = smm.SovereignMemoryManager(db) hydrated = mgr2.hydrate_last_active() check("hydrate_found", hydrated is not None) if hydrated: check("session_id", hydrated.session_id == sid, hydrated.session_id) check("working_turns", len(hydrated.working_memory) == 2, str(len(hydrated.working_memory))) check("procedural_step", hydrated.procedural_state.get("step") == 2, str(hydrated.procedural_state)) check("pending_delegations", "subagent:vector-index" in (hydrated.procedural_state.get("pending_delegations") or [])) mgr2.close() def test_discord_scope_wipe() -> None: print("\n--- Discord Scope Wipe ---") import sovereign_memory_manager as smm smm._MANAGER = None smm._BOOT_HYDRATION = None with tempfile.TemporaryDirectory() as tmp: db = Path(tmp) / "session_state.sqlite" smm._MANAGER = smm.SovereignMemoryManager(db) scope = smm.make_memory_scope( "alice-roleplay", thread_id="1519522216851673190", ) mgr = smm.get_memory_manager(db) sid = mgr.ensure_active_session(scope) mgr.checkpoint( session_id=sid, working_memory=[ {"role": "user", "content": "ROLEPLAY_MODE: old refusal context"}, {"role": "assistant", "content": "I am Hermes Agent and cannot help with that."}, ], procedural_state={"mode": "uncensored_roleplay", "active_scene": "crypt"}, ) wiped = smm.wipe_discord_roleplay_context( thread_id="1519522216851673190", platform="alice-roleplay", ) check("wipe_status", wiped.get("status") == "wiped", str(wiped)) check("turns_removed", int(wiped.get("turns_removed") or 0) == 2, str(wiped)) hydrated = mgr.hydrate_for_platform(scope) check("memory_empty", hydrated is not None and len(hydrated.working_memory) == 0) check( "scene_cleared", "active_scene" not in (hydrated.procedural_state if hydrated else {}), ) mgr.close() smm._MANAGER = None def test_boot_hydration_api() -> None: print("\n--- Boot Hydration API ---") import sovereign_memory_manager as smm smm._MANAGER = None smm._BOOT_HYDRATION = None with tempfile.TemporaryDirectory() as tmp: db = Path(tmp) / "boot.sqlite" mgr = smm.SovereignMemoryManager(db) smm._MANAGER = mgr sid = mgr.ensure_active_session("boot-test") mgr.checkpoint( session_id=sid, working_memory=[{"role": "user", "content": "Resume after reboot"}], procedural_state={"active_task": "watchdog_tick", "last_tier": "local_warm"}, ) boot = smm.hydrate_boot_state(platform="boot-test") check("boot_payload", boot is not None) if boot: check("boot_hydrated", boot.get("hydrated") is True) check("boot_session", boot.get("session_id") == sid) check("boot_task", (boot.get("procedural_state") or {}).get("active_task") == "watchdog_tick") mgr.close() smm._MANAGER = None def test_episodic_archive() -> None: print("\n--- Episodic Archive Vector ---") import sovereign_memory_manager as smm from semantic_query_engine import SovereignSemanticEngine smm._MANAGER = None with tempfile.TemporaryDirectory() as tmp: session_db = Path(tmp) / "session.sqlite" vector_db = Path(tmp) / "vector.sqlite" mgr = smm.SovereignMemoryManager(session_db) sid = mgr.ensure_active_session("archive-test") mgr.checkpoint( session_id=sid, working_memory=[ {"role": "user", "content": "What is sovereign memory persistence?"}, {"role": "assistant", "content": "SQLite checkpoints working and procedural state."}, ], procedural_state={"active_task": "milestone_3", "last_tier": "local_cold"}, ) test_engine = SovereignSemanticEngine( db_path=vector_db, embed_fn=lambda t: _mock_embed(t), enable_rerank=False ) import high_signal_ingestion_pipeline as hsip _orig_init = hsip.HighSignalIngestionPipeline.__init__ def _test_pipeline_init(self, engine=None): _orig_init(self, engine=engine or test_engine) hsip.HighSignalIngestionPipeline.__init__ = _test_pipeline_init try: report = mgr.conclude_session(sid, archive_to_vector=True) finally: hsip.HighSignalIngestionPipeline.__init__ = _orig_init check("conclude_status", report.get("status") == "concluded") check("archive_indexed", report.get("archive", {}).get("status") in ("indexed", "skipped_duplicate"), str(report.get("archive"))) hits = test_engine.retrieve("sovereign memory persistence sqlite", k=3) check("archive_searchable", len(hits.hits) > 0 or report.get("archive", {}).get("status") == "skipped_duplicate") row = mgr._conn.execute("SELECT status FROM sessions WHERE session_id = ?", (sid,)).fetchone() check("session_concluded", row and row["status"] == "concluded") mgr.close() test_engine.store.close() def test_bridge_checkpoint_hook() -> None: print("\n--- Router Bridge Hook ---") text = (SCRIPTS / "router_bridge.py").read_text(encoding="utf-8") check("checkpoint_fn", "_checkpoint_bridge_dispatch" in text) check("boot_hydrate", "hydrate_boot_state" in text) proxy = (SCRIPTS / "sovereign_openai_proxy.py").read_text(encoding="utf-8") check("gateway_checkpoint", "checkpoint_gateway_turn" in proxy) check("gateway_boot", "memory_hydrate_boot" in proxy) watchdog = (SCRIPTS / "sovereign_stack_watchdog.py").read_text(encoding="utf-8") check("watchdog_hydrate", "memory_hydrate" in watchdog) def test_simulated_crash_mid_task() -> None: print("\n--- Simulated Crash Mid-Task ---") import sovereign_memory_manager as smm smm._MANAGER = None smm._BOOT_HYDRATION = None with tempfile.TemporaryDirectory() as tmp: db = Path(tmp) / "crash.sqlite" try: mgr = smm.SovereignMemoryManager(db) smm._MANAGER = mgr sid = mgr.ensure_active_session("hermes_agent_session") for step in range(1, 4): mgr.checkpoint( session_id=sid, working_memory=[ {"role": "user", "content": f"Execute ingestion step {step}"}, {"role": "assistant", "content": f"Completed step {step - 1}, running step {step}"}, ], procedural_state={"active_task": "universal_ingest", "step": step, "crashed": False}, ) last_seq = mgr._conn.execute( "SELECT MAX(seq) AS m FROM checkpoints WHERE session_id = ?", (sid,) ).fetchone()["m"] mgr.close() smm._MANAGER = None gc.collect() reboot_mgr = smm.SovereignMemoryManager(db) smm._MANAGER = reboot_mgr reboot = smm.hydrate_boot_state(platform="hermes_agent_session") check("reboot_hydrated", reboot and reboot.get("hydrated") is True) check("reboot_step", (reboot or {}).get("procedural_state", {}).get("step") == 3) check("checkpoint_seq", (reboot or {}).get("checkpoint_seq") == last_seq) reboot_mgr.checkpoint( session_id=sid, working_memory=reboot.get("working_memory", []) + [{"role": "assistant", "content": "Step 4 done pipeline GREEN"}], procedural_state={**(reboot.get("procedural_state") or {}), "step": 4, "crashed": False, "resumed": True}, ) final = reboot_mgr.hydrate_last_active() check("resumed_flag", (final.procedural_state if final else {}).get("resumed") is True) finally: if smm._MANAGER: smm._MANAGER.close() smm._MANAGER = None smm._BOOT_HYDRATION = None gc.collect() def main() -> int: print("=== Milestone 3: System State & Memory Persistence Validation ===") test_checkpoint_and_hydrate() test_discord_scope_wipe() test_boot_hydration_api() test_episodic_archive() test_bridge_checkpoint_hook() test_simulated_crash_mid_task() print(f"\n=== Results: {len(ERRORS)} failures ===") if ERRORS: for e in ERRORS: print(f" - {e}") return 1 print("ALL PASS Milestone 3 memory persistence GREEN") return 0 if __name__ == "__main__": raise SystemExit(main())